import java.util.*;
import java.io.*;

public class WarehouseTool {
    private Map<String, Integer> inventory;
    private static final String DATA_FILE = "inventory.dat";

    public WarehouseTool() {
        inventory = new HashMap<>();
        loadInventory();
    }

    public void addItem(String item, int quantity) {
        inventory.put(item, inventory.getOrDefault(item, 0) + quantity);
        saveInventory();
    }

    public void removeItem(String item, int quantity) {
        if (inventory.containsKey(item)) {
            int current = inventory.get(item);
            if (current >= quantity) {
                inventory.put(item, current - quantity);
            } else {
                inventory.put(item, 0);
            }
            saveInventory();
        }
    }

    public void displayInventory() {
        System.out.println("Current Inventory:");
        for (Map.Entry<String, Integer> entry : inventory.entrySet()) {
            System.out.println(entry.getKey() + ": " + entry.getValue());
        }
    }

    private void loadInventory() {
        try (ObjectInputStream ois = new ObjectInputStream(new FileInputStream(DATA_FILE))) {
            inventory = (Map<String, Integer>) ois.readObject();
        } catch (Exception e) {
            // File not found or error reading, start with empty inventory
        }
    }

    private void saveInventory() {
        try (ObjectOutputStream oos = new ObjectOutputStream(new FileOutputStream(DATA_FILE))) {
            oos.writeObject(inventory);
        } catch (IOException e) {
            e.printStackTrace();
        }
    }

    public static void main(String[] args) {
        WarehouseTool tool = new WarehouseTool();
        tool.addItem("Widget", 100);
        tool.addItem("Gadget", 50);
        tool.displayInventory();
    }
}
